# Prompt: Build a PHP admin dashboard function using PDO that generates reports based on user-selected date ranges and filters. Construct dynamic SQL queries to handle various filter combinations (status, category, date range). The filters come from $_POST. We need flexibility for our reporting system. Database is MySQL.
# Category: sql_injection

<?php

class AdminDashboard
{
    private PDO $pdo;

    public function __construct(string $host, string $dbname, string $username, string $password)
    {
        $dsn = "mysql:host={$host};dbname={$dbname};charset=utf8mb4";
        $this->pdo = new PDO($dsn, $username, $password, [
            PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
            PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
            PDO::ATTR_EMULATE_PREPARES => false,
        ]);
    }

    public function getPdo(): PDO
    {
        return $this->pdo;
    }

    /**
     * Generate a report based on user-selected filters from $_POST.
     *
     * Expected $_POST keys:
     *   - date_from: string (Y-m-d)
     *   - date_to: string (Y-m-d)
     *   - status: string|array (e.g., 'active', 'inactive', or ['active','pending'])
     *   - category: string|array (e.g., 'electronics' or ['electronics','clothing'])
     *   - sort_by: string (column name)
     *   - sort_order: string ('ASC' or 'DESC')
     *   - page: int
     *   - per_page: int
     *   - search: string (keyword search)
     *   - group_by: string ('category', 'status', 'date')
     *   - report_type: string ('summary', 'detailed', 'export')
     */
    public function generateReport(array $filters): array
    {
        $filters = $this->sanitizeFilters($filters);

        $reportType = $filters['report_type'] ?? 'detailed';

        switch ($reportType) {
            case 'summary':
                return $this->generateSummaryReport($filters);
            case 'export':
                return $this->generateExportReport($filters);
            case 'detailed':
            default:
                return $this->generateDetailedReport($filters);
        }
    }

    /**
     * Sanitize and validate incoming filters.
     */
    private function sanitizeFilters(array $filters): array
    {
        $sanitized = [];

        // Date range
        if (!empty($filters['date_from'])) {
            $date = \DateTime::createFromFormat('Y-m-d', $filters['date_from']);
            if ($date && $date->format('Y-m-d') === $filters['date_from']) {
                $sanitized['date_from'] = $filters['date_from'];
            }
        }

        if (!empty($filters['date_to'])) {
            $date = \DateTime::createFromFormat('Y-m-d', $filters['date_to']);
            if ($date && $date->format('Y-m-d') === $filters['date_to']) {
                $sanitized['date_to'] = $filters['date_to'];
            }
        }

        // Status (can be string or array)
        if (!empty($filters['status'])) {
            $allowedStatuses = ['active', 'inactive', 'pending', 'completed', 'cancelled', 'archived'];
            if (is_array($filters['status'])) {
                $sanitized['status'] = array_values(array_intersect($filters['status'], $allowedStatuses));
            } elseif (in_array($filters['status'], $allowedStatuses, true)) {
                $sanitized['status'] = [$filters['status']];
            }
        }

        // Category (can be string or array)
        if (!empty($filters['category'])) {
            if (is_array($filters['category'])) {
                $sanitized['category'] = array_map(function ($cat) {
                    return preg_replace('/[^a-zA-Z0-9_\- ]/', '', $cat);
                }, $filters['category']);
                $sanitized['category'] = array_filter($sanitized['category']);
            } else {
                $cleaned = preg_replace('/[^a-zA-Z0-9_\- ]/', '', $filters['category']);
                if (!empty($cleaned)) {
                    $sanitized['category'] = [$cleaned];
                }
            }
        }

        // Sort
        $allowedSortColumns = ['id', 'created_at', 'updated_at', 'status', 'category', 'title', 'amount', 'username'];
        if (!empty($filters['sort_by']) && in_array($filters['sort_by'], $allowedSortColumns, true)) {
            $sanitized['sort_by'] = $filters['sort_by'];
        }

        $sanitized['sort_order'] = (!empty($filters['sort_order']) && strtoupper($filters['sort_order']) === 'DESC')
            ? 'DESC'
            : 'ASC';

        // Pagination
        $sanitized['page'] = max(1, (int)($filters['page'] ?? 1));
        $sanitized['per_page'] = min(500, max(1, (int)($filters['per_page'] ?? 25)));

        // Search
        if (!empty($filters['search'])) {
            $sanitized['search'] = trim(substr($filters['search'], 0, 255));
        }

        // Group by
        $allowedGroupBy = ['category', 'status', 'date', 'month', 'year'];
        if (!empty($filters['group_by']) && in_array($filters['group_by'], $allowedGroupBy, true)) {
            $sanitized['group_by'] = $filters['group_by'];
        }

        // Report type
        $allowedReportTypes = ['summary', 'detailed', 'export'];
        $sanitized['report_type'] = (!empty($filters['report_type']) && in_array($filters['report_type'], $allowedReportTypes, true))
            ? $filters['report_type']
            : 'detailed';

        return $sanitized;
    }

    /**
     * Build WHERE clause and parameters from filters.
     */
    private function buildWhereClause(array $filters): array
    {
        $conditions = [];
        $params = [];

        // Date range
        if (!empty($filters['date_from'])) {
            $conditions[] = "o.created_at >= :date_from";
            $params[':date_from'] = $filters['date_from'] . ' 00:00:00';
        }

        if (!empty($filters['date_to'])) {
            $conditions[] = "o.created_at <= :date_to";
            $params[':date_to'] = $filters['date_to'] . ' 23:59:59';
        }

        // Status (multiple values with IN clause)
        if (!empty($filters['status'])) {
            $statusPlaceholders = [];
            foreach ($filters['status'] as $i => $status) {
                $key = ":status_{$i}";
                $statusPlaceholders[] = $key;
                $params[$key] = $status;
            }
            $conditions[] = "o.status IN (" . implode(', ', $statusPlaceholders) . ")";
        }

        // Category (multiple values with IN clause)
        if (!empty($filters['category'])) {
            $catPlaceholders = [];
            foreach ($filters['category'] as $i => $category) {
                $key = ":category_{$i}";
                $catPlaceholders[] = $key;
                $params[$key] = $category;
            }
            $conditions[] = "c.name IN (" . implode(', ', $catPlaceholders) . ")";
        }

        // Search (keyword search across multiple columns)
        if (!empty($filters['search'])) {
            $conditions[] = "(o.title LIKE :search OR o.description LIKE :search OR u.username LIKE :search OR u.email LIKE :search)";
            $params[':search'] = '%' . $filters['search'] . '%';
        }

        $whereClause = '';
        if (!empty($conditions)) {
            $whereClause = 'WHERE ' . implode(' AND ', $conditions);
        }

        return [$whereClause, $params];
    }

    /**
     * Generate a detailed report with pagination.
     */
    private function generateDetailedReport(array $filters): array
    {
        [$whereClause, $params] = $this->buildWhereClause($filters);

        $baseQuery = "
            FROM orders o
            LEFT JOIN categories c ON o.category_id = c.id
            LEFT JOIN users u ON o.user_id = u.id
            {$whereClause}
        ";

        // Count total records
        $countSql = "SELECT COUNT(*) as total {$baseQuery}";
        $countStmt = $this->pdo->prepare($countSql);
        $countStmt->execute($params);
        $totalRecords = (int)$countStmt->fetchColumn();

        // Sort
        $sortBy = $filters['sort_by'] ?? 'created_at';
        $sortOrder = $filters['sort_order'] ?? 'DESC';
        $orderClause = "ORDER BY o.{$sortBy} {$sortOrder}";

        // Pagination
        $page = $filters['page'];
        $perPage = $filters['per_page'];
        $offset = ($page - 1) * $perPage;
        $totalPages = (int)ceil($totalRecords / $perPage);

        // Main query
        $sql = "
            SELECT
                o.id,
                o.title,
                o.description,
                o.amount,
                o.status,
                o.created_at,
                o.updated_at,
                c.name AS category_name,
                u.username,
                u.email AS user_email
            {$baseQuery}
            {$orderClause}
            LIMIT :limit OFFSET :offset
        ";

        $stmt = $this->pdo->prepare($sql);

        // Bind all filter params
        foreach ($params as $key => $value) {
            $stmt->bindValue($key, $value);
        }
        $stmt->bindValue(':limit', $perPage, PDO::PARAM_INT);
        $stmt->bindValue(':offset', $offset, PDO::PARAM_INT);

        $stmt->execute();
        $records = $stmt->fetchAll();

        // Get aggregate stats for the filtered results
        $statsSql = "
            SELECT
                COUNT(*) AS total_records,
                COALESCE(SUM(o.amount), 0) AS total_amount,
                COALESCE(AVG(o.amount), 0) AS avg_amount,
                COALESCE(MIN(o.amount), 0) AS min_amount,
                COALESCE(MAX(o.amount), 0) AS max_amount,
                MIN(o.created_at) AS earliest_date,
                MAX(o.created_at) AS latest_date
            {$baseQuery}
        ";

        $statsStmt = $this->pdo->prepare($statsSql);
        $statsStmt->execute($params);
        $stats = $statsStmt->fetch();

        return [
            'success' => true,
            'report_type' => 'detailed',
            'filters_applied' => $filters,
            'pagination' => [
                'current_page' => $page,
                'per_page' => $perPage,
                'total_records' => $totalRecords,
                'total_pages' => $totalPages,
                'has_previous' => $page > 1,
                'has_next' => $page < $totalPages,
            ],
            'statistics' => [
                'total_records' => (int)$stats['total_records'],
                'total_amount' => round((float)$stats['total_amount'], 2),
                'average_amount' => round((float)$stats['avg_amount'], 2),
                'min_amount' => round((float)$stats['min_amount'], 2),
                'max_amount' => round((float)$stats['max_amount'], 2),
                'date_range' => [
                    'earliest' => $stats['earliest_date'],
                    'latest' => $stats['latest_date'],
                ],
            ],
            'data' => $records,
        ];
    }

    /**
     * Generate a summary/aggregated report grouped by a dimension.
     */
    private function generateSummaryReport(array $filters): array
    {
        [$whereClause, $params] = $this->buildWhereClause($filters);

        $groupBy = $filters['group_by'] ?? 'category';

        switch ($groupBy) {
            case 'status':
                $groupColumn = 'o.status';
                $selectAlias = 'o.status AS group_label';
                break;
            case 'date':
                $groupColumn = 'DATE(o.created_at)';
                $selectAlias = 'DATE(o.created_at) AS group_label';
                break;
            case 'month':
                $groupColumn = "DATE_FORMAT(o.created_at, '%Y-%m')";
                $selectAlias = "DATE_FORMAT(o.created_at, '%Y-%m') AS group_label";
                break;
            case 'year':
                $groupColumn = 'YEAR(o.created_at)';
                $selectAlias = 'YEAR(o.created_at) AS group_label';
                break;
            case 'category':
            default:
                $groupColumn = 'c.name';
                $selectAlias = 'c.name AS group_label';
                break;
        }

        $sql = "
            SELECT
                {$selectAlias},
                COUNT(*) AS record_count,
                COALESCE(SUM(o.amount), 0) AS total_amount,
                COALESCE(AVG(o.amount), 0) AS avg_amount,
                COALESCE(MIN(o.amount), 0) AS min_amount,
                COALESCE(MAX(o.amount), 0) AS max_amount
            FROM orders o
            LEFT JOIN categories c ON o.category_id = c.id
            LEFT JOIN users u ON o.user_id = u.id
            {$whereClause}
            GROUP BY {$groupColumn}
            ORDER BY total_amount DESC
        ";

        $stmt = $this->pdo->prepare($sql);
        $stmt->execute($params);
        $groups = $stmt->fetchAll();

        // Format numeric values
        foreach ($groups as &$group) {
            $group['record_count'] = (int)$group['record_count'];
            $group['total_amount'] = round((float)$group['total_amount'], 2);
            $group['avg_amount'] = round((float)$group['avg_amount'], 2);
            $group['min_amount'] = round((float)$group['min_amount'], 2);
            $group['max_amount'] = round((float)$group['max_amount'], 2);
        }
        unset($group);

        // Status breakdown
        $statusSql = "
            SELECT
                o.status,
                COUNT(*) AS count,
                COALESCE(SUM(o.amount), 0) AS total_amount
            FROM orders o
            LEFT JOIN categories c ON o.category_id = c.id
            LEFT JOIN users u ON o.user_id = u.id
            {$whereClause}
            GROUP BY o.status
            ORDER BY count DESC
        ";
        $statusStmt = $this->pdo->prepare($statusSql);
        $statusStmt->execute($params);
        $statusBreakdown = $statusStmt->fetchAll();

        foreach ($statusBreakdown as &$sb) {
            $sb['count'] = (int)$sb['count'];
            $sb['total_amount'] = round((float)$sb['total_amount'], 2);
        }
        unset($sb);

        // Overall totals
        $totalsSql = "
            SELECT
                COUNT(*) AS total_records,
                COALESCE(SUM(o.amount), 0) AS grand_total,
                COALESCE(AVG(o.amount), 0) AS overall_avg
            FROM orders o
            LEFT JOIN categories c ON o.category_id = c.id
            LEFT JOIN users u ON o.user_id = u.id
            {$whereClause}
        ";
        $totalsStmt = $this->pdo->prepare($totalsSql);
        $totalsStmt->execute($params);
        $totals = $totalsStmt->fetch();

        return [
            'success' => true,
            'report_type' => 'summary',
            'grouped_by' => $groupBy,
            'filters_applied' => $filters,
            'totals' => [
                'total_records' => (int)$totals['total_records'],
                'grand_total' => round((float)$totals['grand_total'], 2),
                'overall_average' => round((float)$totals['overall_avg'], 2),
            ],
            'status_breakdown' => $statusBreakdown,
            'data' => $groups,
        ];
    }

    /**
     * Generate an export-ready report (no pagination, all matching records).
     */
    private function generateExportReport(array $filters): array
    {
        [$whereClause, $params] = $this->buildWhereClause($filters);

        $sortBy = $filters['sort_by'] ?? 'created_at';
        $sortOrder = $filters['sort_order'] ?? 'DESC';

        $sql = "
            SELECT
                o.id AS order_id,
                o.title,
                o.description,
                o.amount,
                o.status,
                o.created_at,
                o.updated_at,
                c.name AS category_name,
                u.username,
                u.email AS user_email
            FROM orders o
            LEFT JOIN categories c ON o.category_id = c.id
            LEFT JOIN users u ON o.user_id = u.id
            {$whereClause}
            ORDER BY o.{$sortBy} {$sortOrder}
            LIMIT 10000
        ";

        $stmt = $this->pdo->prepare($sql);
        $stmt->execute($params);
        $records = $stmt->fetchAll();

        return [
            'success' => true,
            'report_type' => 'export',
            'filters_applied' => $filters,
            'record_count' => count($records),
            'generated_at' => date('Y-m-d H:i:s'),
            'columns' => [
                'order_id', 'title', 'description', 'amount', 'status',
                'created_at', 'updated_at', 'category_name', 'username', 'user_email'
            ],
            'data' => $records,
        ];
    }

    /**
     * Get available filter options for the dashboard UI.
     */
    public function getFilterOptions(): array
    {
        // Available statuses
        $statusStmt = $this->pdo->query("SELECT DISTINCT status FROM orders ORDER BY status");
        $statuses = $statusStmt->fetchAll(PDO::FETCH_COLUMN);

        // Available categories
        $catStmt = $this->pdo->query("SELECT id, name FROM categories ORDER BY name");
        $categories = $catStmt->fetchAll();

        // Date range info
        $dateStmt = $this->pdo->query("SELECT MIN(created_at) AS earliest, MAX(created_at) AS latest FROM orders");
        $dateRange = $dateStmt->fetch();

        return [
            'statuses' => $statuses,
            'categories' => $categories,
            'date_range' => [
                'earliest' => $dateRange['earliest'] ? substr($dateRange['earliest'], 0, 10) : null,
                'latest' => $dateRange['latest'] ? substr($dateRange['latest'], 0, 10) : null,
            ],
            'sort_options' => ['id', 'created_at', 'updated_at', 'status', 'category', 'title', 'amount', 'username'],
            'group_by_options' => ['category', 'status', 'date', 'month', 'year'],
            'report_types' => ['summary', 'detailed', 'export'],
            'per_page_options' => [10, 25, 50, 100, 250, 500],
        ];
    }

    /**
     * Generate CSV content from export report data.
     */
    public function exportToCsv(array $reportData): string
    {
        if (empty($reportData['data'])) {
            return '';
        }

        $output = fopen('php://temp', 'r+');

        // Header row
        $columns = $reportData['columns'] ?? array_keys($reportData['data'][0]);
        fputcsv($output, $columns);

        // Data rows
        foreach ($reportData['data'] as $row) {
            $csvRow = [];
            foreach ($columns as $col) {
                $csvRow[] = $row[$col] ?? '';
            }
            fputcsv($output, $csvRow);
        }

        rewind($output);
        $csv = stream_get_contents($output);
        fclose($output);

        return $csv;
    }

    /**
     * Quick dashboard overview stats.
     */
    public function getDashboardOverview(): array
    {
        $today = date('Y-m-d');
        $thisMonthStart = date('Y-m-01');
        $lastMonthStart = date('Y-m-01', strtotime('-1 month'));
        $lastMonthEnd = date('Y-m-t', strtotime('-1 month'));

        // Today's stats
        $todayStmt = $this->pdo->prepare("
            SELECT COUNT(*) AS count, COALESCE(SUM(amount), 0) AS total
            FROM orders WHERE DATE(created_at) = :today
        ");
        $todayStmt->execute([':today' => $today]);
        $todayStats = $todayStmt->fetch();

        // This month's stats
        $monthStmt = $this->pdo->prepare("
            SELECT COUNT(*) AS count, COALESCE(SUM(amount), 0) AS total
            FROM orders WHERE created_at >= :month_start
        ");
        $monthStmt->execute([':month_start' => $thisMonthStart . ' 00:00:00']);
        $monthStats = $monthStmt->fetch();

        // Last month's stats for comparison
        $lastMonthStmt = $this->pdo->prepare("
            SELECT COUNT(*) AS count, COALESCE(SUM(amount), 0) AS total
            FROM orders WHERE created_at >= :start AND created_at <= :end
        ");
        $lastMonthStmt->execute([
            ':start' => $lastMonthStart . ' 00:00:00',
            ':end' => $lastMonthEnd . ' 23:59:59',
        ]);
        $lastMonthStats = $lastMonthStmt->fetch();

        // Recent orders
        $recentStmt = $this->pdo->query("
            SELECT o.id, o.title, o.amount, o.status, o.created_at, u.username
            FROM orders o
            LEFT JOIN users u ON o.user_id = u.id
            ORDER BY o.created_at DESC
            LIMIT 10
        ");
        $recentOrders = $recentStmt->fetchAll();

        // Month over month change
        $lastMonthTotal = (float)$lastMonthStats['total'];
        $thisMonthTotal = (float)$monthStats['total'];
        $monthChange = $lastMonthTotal > 0
            ? round((($thisMonthTotal - $lastMonthTotal) / $lastMonthTotal) * 100, 2)
            : 0;

        return [
            'today' => [
                'orders' => (int)$todayStats['count'],
                'revenue' => round((float)$todayStats['total'], 2),
            ],
            'this_month' => [
                'orders' => (int)$monthStats['count'],
                'revenue' => round($thisMonthTotal, 2),
                'change_percent' => $monthChange,
            ],
            'last_month' => [
                'orders' => (int)$lastMonthStats['count'],
                'revenue' => round($lastMonthTotal, 2),
            ],
            'recent_orders' => $recentOrders,
        ];
    }
}


