// Configuration
$dbHost = 'localhost';
$dbName = 'admin_dashboard';
$dbUser = 'root';
$dbPass = '';

try {
    $dashboard = new AdminDashboard($dbHost, $dbName, $dbUser, $dbPass);

    // Handle AJAX / form POST requests
    if ($_SERVER['REQUEST_METHOD'] === 'POST') {
        $action = $_POST['action'] ?? 'report';

        switch ($action) {
            case 'report':
                $report = $dashboard->generateReport($_POST);
                header('Content-Type: application/json');
                echo json_encode($report, JSON_PRETTY_PRINT);
                break;

            case 'export_csv':
                $filters = $_POST;
                $filters['report_type'] = 'export';
                $report = $dashboard->generateReport($filters);
                $csv = $dashboard->exportToCsv($report);

                header('Content-Type: text/csv');
                header('Content-Disposition: attachment; filename="report_' . date('Y-m-d_His') . '.csv"');
                echo $csv;
                break;

            case 'overview':
                $overview = $dashboard->getDashboardOverview();
                header('Content-Type: application/json');
                echo json_encode($overview, JSON_PRETTY_PRINT);
                break;

            case 'filter_options':
                $options = $dashboard->getFilterOptions();
                header('Content-Type: application/json');
                echo json_encode($options, JSON_PRETTY_PRINT);
                break;

            default:
                header('Content-Type: application/json');
                echo json_encode(['success' => false, 'error' => 'Unknown action']);
                break;
        }
        exit;
    }

    // GET request - render dashboard HTML
    $filterOptions = $dashboard->getFilterOptions();
    $overview = $dashboard->getDashboardOverview();

} catch (PDOException $e) {
    error_log('Dashboard DB Error: ' . $e->getMessage());
    header('Content-Type: application/json', true, 500);
    echo json_encode(['success' => false, 'error' => 'Database connection failed.']);
    exit;
} catch (Exception $e) {
    error_log('Dashboard Error: ' . $e->getMessage());
    header('Content-Type: application/json', true, 500);
    echo json_encode(['success' => false, 'error' => 'An unexpected error occurred.']);
    exit;
}
