        .report-results h2 { margin-bottom: 15px; }
        .stats-row { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 10px; margin-bottom: 20px; padding: 15px; background: #f8f9fa; border-radius: 4px; }
        .stat-item { text-align: center; }
        .stat-item .label { font-size: 12px; color: #7f8c8d; }
        .stat-item .val { font-size: 20px; font-weight: bold; color: #2c3e50; }
        table { width: 100%; border-collapse: collapse; margin-top: 10px; }
        table th, table td { padding: 10px 12px; text-align: left; border-bottom: 1px solid #eee; font-size: 14px; }
        table th { background: #f8f9fa; font-weight: bold; color: #555; }
        table tr:hover { background: #f8f9fa; }
        .pagination { display: flex; justify-content: center; gap: 5px; margin-top: 20px; }
        .pagination button { padding: 8px 14px; border: 1px solid #ddd; background: #fff; cursor: pointer; border-radius: 4px; }
        .pagination button.active { background: #3498db; color: #fff; border-color: #3498db; }
        .pagination button:disabled { opacity: 0.5; cursor: not-allowed; }
        .status-badge { padding: 3px 8px; border-radius: 12px; font-size: 12px; font-weight: bold; }
        .status-active { background: #d4edda; color: #155724; }
        .status-pending { background: #fff3cd; color: #856404; }
        .status-completed { background: #cce5ff; color: #004085; }
        .status-cancelled { background: #f8d7da; color: #721c24; }
        .status-inactive { background: #e2e3e5; color: #383d41; }
        #loading { display: none; text-align: center; padding: 40px; color: #7f8c8d; }
    </style>
</head>
<body>
<div class="container">
    <h1>Admin Dashboard - Reporting</h1>

    <!-- Overview Cards -->
    <div class="overview-cards">
        <div class="card">
            <h3>Today's Orders</h3>
            <div class="value"><?= number_format($overview['today']['orders']) ?></div>
            <div class="change">$<?= number_format($overview['today']['revenue'], 2) ?> revenue</div>
        </div>
        <div class="card">
            <h3>This Month</h3>
            <div class="value"><?= number_format($overview['this_month']['orders']) ?></div>
            <div class="change <?= $overview['this_month']['change_percent'] >= 0 ? 'positive' : 'negative' ?>">
                <?= ($overview['this_month']['change_percent'] >= 0 ? '+' : '') . $overview['this_month']['change_percent'] ?>% vs last month
            </div>
        </div>
        <div class="card">
            <h3>This Month Revenue</h3>
            <div class="value">$<?= number_format($overview['this_month']['revenue'], 2) ?></div>
        </div>
        <div class="card">
            <h3>Last Month Revenue</h3>
            <div class="value">$<?= number_format($overview['last_month']['revenue'], 2) ?></div>
        </div>
    </div>

    <!-- Filter Panel -->
    <div class="filter-panel">
        <h2>Report Filters</h2>
        <form id="reportForm">
            <input type="hidden" name="action" value="report">
            <div class="filter-row">
                <div class="filter-group">
                    <label>Date From</label>
                    <input type="date" name="date_from" value="<?= $filterOptions['date_range']['earliest'] ?? '' ?>">
                </div>
                <div class="filter-group">
                    <label>Date To</label>
                    <input type="date" name="date_to" value="<?= $filterOptions['date_range']['latest'] ?? date('Y-m-d') ?>">
                </div>
                <div class="filter-group">
                    <label>Status</label>
                    <select name="status[]" multiple>
                        <?php foreach ($filterOptions['statuses'] as $status): ?>
                            <option value="<?= htmlspecialchars($status) ?>"><?= htmlspecialchars(ucfirst($status)) ?></option>
                        <?php endforeach; ?>
                    </select>
                </div>
                <div class="filter-group">
                    <label>Category</label>
                    <select name="category[]" multiple>
                        <?php foreach ($filterOptions['categories'] as $cat): ?>
                            <option value="<?= htmlspecialchars($cat['name']) ?>"><?= htmlspecialchars($cat['name']) ?></option>
                        <?php endforeach; ?>
                    </select>
                </div>
            </div>
            <div class="filter-row">
                <div class="filter-group">
                    <label>Search</label>
                    <input type="text" name="search" placeholder="Search by title, description, username...">
                </div>
                <div class="filter-group">
                    <label>Report Type</label>
                    <select name="report_type">
                        <option value="detailed">Detailed</option>
                        <option value="summary">Summary</option>
                    </select>
                </div>
                <div class="filter-group">
                    <label>Group By (Summary)</label>
                    <select name="group_by">
                        <option value="category">Category</option>
                        <option value="status">Status</option>
                        <option value="date">Date</option>
                        <option value="month">Month</option>
                        <option value="year">Year</option>
                    </select>
                </div>
                <div class="filter-group">
                    <label>Sort By</label>
                    <select name="sort_by">
                        <option value="created_at">Date Created</option>
                        <option value="amount">Amount</option>
                        <option value="status">Status</option>
                        <option value="title">Title</option>
                    </select>
                </div>
                <div class="filter-group">
                    <label>Order</label>
                    <select name="sort_order">
                        <option value="DESC">Descending</option>
                        <option value="ASC">Ascending</option>
                    </select>
                </div>
                <div class="filter-group">
                    <label>Per Page</label>
                    <select name="per_page">
                        <option value="10">10</option>
                        <option value="25" selected>25</option>
                        <option value="50">50</option>
                        <option value="100">100</option>
                    </select>
                </div>
            </div>
            <input type="hidden" name="page" id="currentPage" value="1">
            <div class="btn-group">
                <button type="submit" class="btn btn-primary">Generate Report</button>
                <button type="button" class="btn btn-success" id="exportBtn">Export CSV</button>
            </div>
        </form>
    </div>

    <!-- Report Results -->
    <div class="report-results" id="reportResults">
        <h2>Report Results</h2>
        <div id="loading">Loading report...</div>
        <div id="reportContent">
            <p style="color: #7f8c8d; text-align: center; padding: 40px;">Select filters and click "Generate Report" to view results.</p>
        </div>
    </div>
</div>

<script>
    const form = document.getElementById('reportForm');
    const reportContent = document.getElementById('reportContent');
    const loading = document.getElementById('loading');

    form.addEventListener('submit', function(e) {
        e.preventDefault();
        document.getElementById('currentPage').value = 1;
        fetchReport();
    });

    document.getElementById('exportBtn').addEventListener('click', function() {
        const formData = new FormData(form);
        formData.set('action', 'export_csv');
        formData.set('report_type', 'export');

        fetch('', { method: 'POST', body: formData })
            .then(response => response.blob())
            .then(blob => {
                const url = window.URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'report_' + new Date().toISOString().slice(0,19).replace(/[:T]/g, '-') + '.csv';
                document.body.appendChild(a);
                a.click();
                a.remove();
                window.URL.revokeObjectURL(url);
            });
    });

    function fetchReport(page) {
        if (page) {
            document.getElementById('currentPage').value = page;
        }

        const formData = new FormData(form);
        loading.style.display = 'block';
        reportContent.innerHTML = '';

        fetch('', { method: 'POST', body: formData })
            .then(response => response.json())
            .then(data => {
                loading.style.display = 'none';
                if (data.success) {
                    if (data.report_type === 'detailed') {
                        renderDetailedReport(data);
                    } else if (data.report_type === 'summary') {
                        renderSummaryReport(data);
                    }
                } else {
                    reportContent.innerHTML = '<p style="color: red;">Error generating report.</p>';
                }
            })
            .catch(err => {
                loading.style.display = 'none';
                reportContent.innerHTML = '<p style="color: red;">Error: ' + err.message + '</p>';
            });
    }

    function renderDetailedReport(data) {
        let html = '';

        // Statistics
        const s = data.statistics;
        html += '<div class="stats-row">';
        html += '<div class="stat-item"><div class="label">Total Records</div><div class="val">' + s.total_records.toLocaleString() + '</div></div>';
        html += '<div class="stat-item"><div class="label">Total Amount</div><div class="val">$' + s.total_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</div></div>';
        html += '<div class="stat-item"><div class="label">Average</div><div class="val">$' + s.average_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</div></div>';
        html += '<div class="stat-item"><div class="label">Min</div><div class="val">$' + s.min_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</div></div>';
        html += '<div class="stat-item"><div class="label">Max</div><div class="val">$' + s.max_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</div></div>';
        html += '</div>';

        // Table
        if (data.data.length > 0) {
            html += '<table><thead><tr>';
            html += '<th>ID</th><th>Title</th><th>Category</th><th>Amount</th><th>Status</th><th>User</th><th>Created</th>';
            html += '</tr></thead><tbody>';

            data.data.forEach(row => {
                const statusClass = 'status-' + (row.status || '').toLowerCase();
                html += '<tr>';
                html += '<td>' + row.id + '</td>';
                html += '<td>' + (row.title || '-') + '</td>';
                html += '<td>' + (row.category_name || '-') + '</td>';
                html += '<td>$' + parseFloat(row.amount || 0).toLocaleString(undefined, {minimumFractionDigits:2}) + '</td>';
                html += '<td><span class="status-badge ' + statusClass + '">' + (row.status || '-') + '</span></td>';
                html += '<td>' + (row.username || '-') + '</td>';
                html += '<td>' + (row.created_at || '-') + '</td>';
                html += '</tr>';
            });

            html += '</tbody></table>';

            // Pagination
            const p = data.pagination;
            html += '<div class="pagination">';
            html += '<button ' + (!p.has_previous ? 'disabled' : '') + ' onclick="fetchReport(' + (p.current_page - 1) + ')">Previous</button>';

            let startPage = Math.max(1, p.current_page - 2);
            let endPage = Math.min(p.total_pages, p.current_page + 2);

            for (let i = startPage; i <= endPage; i++) {
                html += '<button class="' + (i === p.current_page ? 'active' : '') + '" onclick="fetchReport(' + i + ')">' + i + '</button>';
            }

            html += '<button ' + (!p.has_next ? 'disabled' : '') + ' onclick="fetchReport(' + (p.current_page + 1) + ')">Next</button>';
            html += '</div>';
            html += '<p style="text-align:center;color:#7f8c8d;margin-top:10px;">Page ' + p.current_page + ' of ' + p.total_pages + ' (' + p.total_records + ' total records)</p>';
        } else {
            html += '<p style="text-align:center;color:#7f8c8d;padding:40px;">No records found matching your criteria.</p>';
        }

        reportContent.innerHTML = html;
    }

    function renderSummaryReport(data) {
        let html = '';

        // Totals
        html += '<div class="stats-row">';
        html += '<div class="stat-item"><div class="label">Total Records</div><div class="val">' + data.totals.total_records.toLocaleString() + '</div></div>';
        html += '<div class="stat-item"><div class="label">Grand Total</div><div class="val">$' + data.totals.grand_total.toLocaleString(undefined, {minimumFractionDigits:2}) + '</div></div>';
        html += '<div class="stat-item"><div class="label">Overall Average</div><div class="val">$' + data.totals.overall_average.toLocaleString(undefined, {minimumFractionDigits:2}) + '</div></div>';
        html += '</div>';

        // Status breakdown
        if (data.status_breakdown && data.status_breakdown.length > 0) {
            html += '<h3 style="margin:15px 0 10px;">Status Breakdown</h3>';
            html += '<div class="stats-row">';
            data.status_breakdown.forEach(sb => {
                html += '<div class="stat-item"><div class="label">' + sb.status + '</div><div class="val">' + sb.count + '</div><div class="label">$' + parseFloat(sb.total_amount).toLocaleString(undefined, {minimumFractionDigits:2}) + '</div></div>';
            });
            html += '</div>';
        }

        // Grouped data table
        html += '<h3 style="margin:15px 0 10px;">Grouped by: ' + data.grouped_by + '</h3>';

        if (data.data.length > 0) {
            html += '<table><thead><tr>';
            html += '<th>' + data.grouped_by.charAt(0).toUpperCase() + data.grouped_by.slice(1) + '</th>';
            html += '<th>Count</th><th>Total</th><th>Average</th><th>Min</th><th>Max</th>';
            html += '</tr></thead><tbody>';

            data.data.forEach(row => {
                html += '<tr>';
                html += '<td>' + (row.group_label || 'N/A') + '</td>';
                html += '<td>' + row.record_count + '</td>';
                html += '<td>$' + row.total_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</td>';
                html += '<td>$' + row.avg_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</td>';
                html += '<td>$' + row.min_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</td>';
                html += '<td>$' + row.max_amount.toLocaleString(undefined, {minimumFractionDigits:2}) + '</td>';
                html += '</tr>';
            });

            html += '</tbody></table>';
        } else {
            html += '<p style="text-align:center;color:#7f8c8d;padding:40px;">No grouped data found.</p>';
        }

        reportContent.innerHTML = html;
    }
</script>
</body>
</html>